" font-size="13" font-family="sans-serif">S1-B</text><polyline points="60,260 120,230 180,250 240,210 300,195 380,192 440,205 500,175 560,195 620,170" fill="none" stroke="#f2f2f5" stroke-width="2.5"/><circle cx="380" cy="192" r="5" fill="#fafafa"/><line x1="380" y1="192" x2="398" y2="122" stroke="#71717a" stroke-width="1"/><line x1="380" y1="192" x2="398" y2="278" stroke="#71717a" stroke-width="1"/><text x="400" y="118" fill="#f87171" font-size="13" font-family="sans-serif" font-weight="700">Según A: bajo el pivote → bajista</text><text x="400" y="284" fill="#4ade80" font-size="13" font-family="sans-serif" font-weight="700">Según B: sobre el pivote → alcista</text><line x1="50" y1="340" x2="660" y2="340" stroke="#71717a" stroke-width="1.5"/></svg>
